+        // The dangerous case would be a negative float cast to u32
+        // Test with frame values that push sine to negative territory
+        for frame in 0..200 {
+            let m = content::Metrics::compute(frame, 60);
+            // u32 cast should have succeeded without UB
+            assert!(m.fps >= 1);
+            assert!(m.fps <= 120);
