+        // Frame 0 and 1000 should have same memory (both frame%1000 == 0)
+        assert_eq!(m0.memory_bytes, m1000.memory_bytes);
+        // Frame 999 should be the max in the cycle
+        assert_eq!(m999.memory_bytes, 50_000_000 + 999 * 10_000);
